<script setup lang="ts">
import { computed, ref } from 'vue'
import { useChat } from '@/composables/useChat'
import { useAgentStore } from '@/stores/agentStore'
import { useSessionStore } from '@/stores/sessionStore'
import { estimateSessionContextBreakdown } from '@/opencodeClient/contextBreakdown'
import { createSessionContextFormatter } from '@/opencodeClient/contextFormat'
import type { SessionContextBreakdownKey, SessionContextBreakdownSegment } from '@/opencodeClient/contextBreakdown'
const emit = defineEmits<{ (e: 'close'): void }>()
const { openCodeContextUsage, messages: chatMessages } = useChat()
const agentStore = useAgentStore()
const sessionStore = useSessionStore()
const BREAKDOWN_COLOR: Record<SessionContextBreakdownKey, string> = { system: '#4fc1e8', user: '#a0d468', assistant: '#ac92ec', tool: '#f6bb42', other: '#656d78' }
const formatter = createSessionContextFormatter('zh-CN')
const sessionInfo = computed(() => { const id = sessionStore.activeSessionId; if (!id) return null; return sessionStore.projectSessions.find(s => s.id === id) ?? null })
const metrics = computed(() => { const c = openCodeContextUsage.value; if (!c) return null; return { providerLabel: c.providerID ?? 'opencode', modelLabel: c.modelLabel ?? c.modelID ?? '\u2014', limit: c.limit, input: c.input, output: c.output, reasoning: c.reasoning, cacheRead: c.cacheRead, cacheWrite: c.cacheWrite, total: c.total, usage: c.usage, cost: c.cost, messageCount: c.messageCount, userMessages: c.userMessages, assistantMessages: c.assistantMessages, lastMessageAt: c.lastMessageAt } })
const counts = computed(() => ({ all: metrics.value?.messageCount ?? chatMessages.value.length, user: metrics.value?.userMessages ?? chatMessages.value.filter(m => m.role === 'user').length, assistant: metrics.value?.assistantMessages ?? chatMessages.value.filter(m => m.role === 'assistant').length }))
const systemPrompt = computed(() => { for (let i = chatMessages.value.length - 1; i >= 0; i--) { const m = chatMessages.value[i]; if (m.role !== 'user') continue; const sys = (m as any).system ?? (m as any).systemPrompt; if (typeof sys === 'string' && sys.trim()) return sys.trim() } return undefined })
const breakdown = computed<SessionContextBreakdownSegment[]>(() => { const c = openCodeContextUsage.value; if (!c?.input) return []; const msgs = chatMessages.value.map(m => ({ id: m.id, role: m.role })); const parts: Record<string, any[]> = {}; for (const m of chatMessages.value) { const text = typeof m.content === 'string' ? m.content : ''; if (text) parts[m.id] = [{ type: 'text', text }] }; return estimateSessionContextBreakdown({ messages: msgs as any, parts, input: c.input, systemPrompt: systemPrompt.value }) })
const breakdownLabel = (key: SessionContextBreakdownKey) => { const map: Record<SessionContextBreakdownKey, string> = { system: '\u7cfb\u7edf', user: '\u7528\u6237', assistant: '\u52a9\u624b', tool: '\u5de5\u5177\u8c03\u7528', other: '\u5176\u4ed6' }; return map[key] ?? key }
const stats = computed(() => { const m = metrics.value; const c = counts.value; const info = sessionInfo.value; return [{ label: '\u4f1a\u8bdd', value: info?.title ?? sessionStore.activeSessionId ?? '\u2014' },{ label: '\u6d88\u606f\u6570', value: String(c.all) },{ label: '\u63d0\u4f9b\u5546', value: m?.providerLabel ?? '\u2014' },{ label: '\u6a21\u578b', value: m?.modelLabel ?? '\u2014' },{ label: '\u4e0a\u4e0b\u6587\u9650\u5236', value: formatter.number(m?.limit) },{ label: '\u603b Token', value: formatter.number(m?.total) },{ label: '\u4f7f\u7528\u7387', value: formatter.percent(m?.usage) },{ label: '\u8f93\u5165 Token', value: formatter.number(m?.input) },{ label: '\u8f93\u51fa Token', value: formatter.number(m?.output) },{ label: '\u63a8\u7406 Token', value: formatter.number(m?.reasoning) },{ label: '\u7f13\u5b58 Token', value: `${formatter.number(m?.cacheRead)} / ${formatter.number(m?.cacheWrite)}` },{ label: '\u7528\u6237\u6d88\u606f', value: String(c.user) },{ label: '\u52a9\u624b\u6d88\u606f', value: String(c.assistant) },{ label: '\u603b\u6210\u672c', value: m?.cost != null ? `US$${m.cost.toFixed(2)}` : '\u2014' },{ label: '\u521b\u5efa\u65f6\u95f4', value: formatter.time(info?.createdAt) },{ label: '\u6700\u540e\u6d3b\u52a8', value: formatter.time(m?.lastMessageAt) }] })
const rawMessages = computed(() => chatMessages.value.map(m => ({ id: m.id, role: m.role, content: typeof m.content === 'string' ? m.content.slice(0, 500) : JSON.stringify(m.content).slice(0, 500), time: m.timestamp, finishReason: (m as any).finishReason })))
const expandedIds = ref<Set<string>>(new Set())
function toggleExpand(id: string) { const next = new Set(expandedIds.value); if (next.has(id)) next.delete(id); else next.add(id); expandedIds.value = next }
function isExpanded(id: string) { return expandedIds.value.has(id) }
</script>
<template><div class="ctx-panel"><div class="ctx-head"><div><h3>上下文用量</h3><span v-if="metrics" class="ctx-head-meta">{{ metrics.providerLabel }} · {{ metrics.modelLabel }}</span></div><button class="ctx-close" @click="emit('close')">✕</button></div><div v-if="!metrics" class="ctx-empty">暂无上下文用量数据</div><template v-else><div class="ctx-stats"><div v-for="(stat, i) in stats" :key="i" class="ctx-stat"><span class="cs-label">{{ stat.label }}</span><span class="cs-value">{{ stat.value }}</span></div></div><div v-if="breakdown.length" class="ctx-breakdown"><div class="cb-title">上下文拆分</div><div class="cb-bar"><span v-for="(seg, i) in breakdown" :key="i" class="cb-seg" :style="{ width: seg.width + '%', background: BREAKDOWN_COLOR[seg.key] }" :title="`${breakdownLabel(seg.key)}: ${formatter.number(seg.tokens)} (${seg.percent}%)`"></span></div><div class="cb-legend"><span v-for="(seg, i) in breakdown" :key="i" class="cb-legend-item"><span class="cb-dot" :style="{ background: BREAKDOWN_COLOR[seg.key] }"></span>{{ breakdownLabel(seg.key) }} {{ seg.percent }}%</span></div><div class="cb-note">输入 token 的大致拆分。"其他"包含工具定义和开销。</div></div><div v-if="systemPrompt" class="ctx-section"><div class="cs-title">系统提示词</div><div class="ctx-sysprompt">{{ systemPrompt }}</div></div><div v-if="rawMessages.length" class="ctx-section"><div class="cs-title">原始消息</div><div class="cm-list"><div v-for="msg in rawMessages" :key="msg.id" class="cm-item"><button class="cm-row" :class="{ expanded: isExpanded(msg.id) }" @click="toggleExpand(msg.id)"><span class="cm-role" :class="msg.role">{{ msg.role }}</span><span class="cm-id">· {{ msg.id }}</span><span class="cm-time">{{ formatter.time(msg.time) }}</span><span class="cm-arrow">▾</span></button><div v-if="isExpanded(msg.id)" class="cm-content"><pre class="cm-json">{{ JSON.stringify({ id: msg.id, role: msg.role, content: msg.content, finishReason: msg.finishReason, time: msg.time }, null, 2) }}</pre></div></div></div></div></template></div></template>
<style scoped>.ctx-panel{background:var(--paper);border:1px solid var(--line);border-radius:10px;margin:0 0 8px;overflow:hidden;font-size:13px;max-height:calc(100vh - 80px);display:flex;flex-direction:column}.ctx-head{display:flex;align-items:center;justify-content:space-between;padding:10px 14px;border-bottom:1px solid var(--line);background:var(--surface);flex-shrink:0}.ctx-head h3{margin:0;font-size:14px;color:var(--ink1)}.ctx-head-meta{font-size:11px;color:var(--ink3);margin-left:8px}.ctx-close{background:none;border:none;cursor:pointer;color:var(--ink3);font-size:16px;padding:2px 6px;border-radius:4px}.ctx-close:hover{background:var(--line);color:var(--ink1)}.ctx-empty{padding:20px;color:var(--ink3);text-align:center}.ctx-stats{display:grid;grid-template-columns:1fr 1fr;gap:1px;background:var(--line);border-bottom:1px solid var(--line);flex-shrink:0}.ctx-stat{padding:8px 14px;background:var(--paper);display:flex;flex-direction:column;gap:2px}.cs-label{font-size:11px;color:var(--ink3);text-transform:uppercase}.cs-value{font-size:13px;font-weight:600;color:var(--ink1);word-break:break-all}.ctx-breakdown{padding:10px 14px 8px;flex-shrink:0}.cb-title,.cs-title{font-size:11px;color:var(--ink3);font-weight:600;margin-bottom:6px;text-transform:uppercase}.cb-bar{display:flex;height:8px;border-radius:4px;overflow:hidden;margin-bottom:6px}.cb-seg{transition:width 0.3s ease;min-width:2px}.cb-legend{display:flex;flex-wrap:wrap;gap:12px;margin-bottom:4px}.cb-legend-item{display:flex;align-items:center;gap:4px;font-size:11px;color:var(--ink2)}.cb-dot{width:8px;height:8px;border-radius:2px;flex-shrink:0}.cb-note{font-size:11px;color:var(--ink3)}.ctx-section{padding:10px 14px 8px;flex-shrink:0}.ctx-sysprompt{background:var(--surface);border:1px solid var(--line);border-radius:6px;padding:8px 10px;font-size:12px;color:var(--ink1);white-space:pre-wrap;max-height:200px;overflow-y:auto;font-family:monospace}.cm-list{flex-shrink:0}.cm-item{border-bottom:1px solid rgba(0,0,0,.04)}.cm-row{display:flex;align-items:center;gap:6px;padding:6px 14px;cursor:pointer;background:none;border:none;width:100%;text-align:left;font-size:11px;color:var(--ink1)}.cm-row:hover{background:var(--surface)}.cm-role{padding:0 4px;border-radius:3px;font-weight:600;font-size:10px;text-transform:uppercase;min-width:44px;text-align:center;flex-shrink:0}.cm-role.user{background:rgba(160,212,104,.15);color:#a0d468}.cm-role.assistant{background:rgba(172,146,236,.15);color:#ac92ec}.cm-role.system{background:rgba(101,109,120,.15);color:#656d78}.cm-role.tool{background:rgba(246,187,66,.15);color:#f6bb42}.cm-id{flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:var(--ink3);font-family:monospace;font-size:10px}.cm-time{color:var(--ink3);white-space:nowrap;flex-shrink:0;font-variant-numeric:tabular-nums}.cm-arrow{color:var(--ink3);font-size:10px;transition:transform 0.15s;flex-shrink:0}.cm-row.expanded .cm-arrow{transform:rotate(180deg)}.cm-content{padding:0 14px 8px}.cm-json{background:var(--surface);border-radius:6px;padding:8px;font-size:11px;color:var(--ink1);max-height:300px;overflow:auto;white-space:pre-wrap;word-break:break-all}</style>
